{
  "schemaVersion": 3,
  "judgeId": "judge_1",
  "batchIndex": 7,
  "comparisons": [
    {
      "leftId": "c10_net_modifications",
      "rightId": "dt_01_concept_06",
      "winnerId": "c10_net_modifications",
      "reason": "c10's mechanism directly impacts the catch (mẻ hàng) and perfectly addresses the Ch 21-30 boundary of sustainable vs destructive exploitation (lưới bát quái). 06 focuses on fuel efficiency, which is good but less directly tied to the core seafood loop."
    },
    {
      "leftId": "c10_net_modifications",
      "rightId": "dt_01_concept_07",
      "winnerId": "dt_01_concept_07",
      "reason": "07 perfectly captures the 'phân loại, bảo quản, chế biến' requirement. Its progression from fresh to dried to standardized product offers a stronger, more scalable 30-chapter marketization arc than net modification."
    },
    {
      "leftId": "c10_net_modifications",
      "rightId": "dt_01_concept_08",
      "winnerId": "c10_net_modifications",
      "reason": "08 relies on finding a new cockle bed, which risks violating the 'không biến ký ức thành tọa độ chính xác' boundary. c10 relies purely on technical skill and physics, offering better agency."
    },
    {
      "leftId": "c10_net_modifications",
      "rightId": "dt_01_concept_09",
      "winnerId": "c10_net_modifications",
      "reason": "c10's mechanism of catching fish translates more directly to the 'bữa cơm đủ' requirement than sorting salt. c10's Ch 21-30 conflict (destructive nets) also fits the sustainability boundary better than 09's weather issue."
    },
    {
      "leftId": "c10_net_modifications",
      "rightId": "dt_01_concept_10",
      "winnerId": "c10_net_modifications",
      "reason": "10's eco-tourism concept is highly anachronistic for a poor Vietnamese fishing village in the late 1980s. c10 is grounded in the era's realities."
    },
    {
      "leftId": "dt_01_concept_01",
      "rightId": "dt_01_concept_02",
      "winnerId": "dt_01_concept_01",
      "reason": "02 struggles with the Ch 1-3 pacing requirement because fish sauce fermentation takes months, making early results difficult. 01 provides immediate food and cash, perfectly hitting 'thành quả sớm'."
    },
    {
      "leftId": "dt_01_concept_01",
      "rightId": "dt_01_concept_03",
      "winnerId": "dt_01_concept_01",
      "reason": "01 directly addresses 'loại hải sản bị đánh giá thấp' and 'chế biến'. While 03 is good, 01's focus on food makes the 'bữa cơm' aspect much more visceral and rewarding in the early chapters."
    },
    {
      "leftId": "dt_01_concept_01",
      "rightId": "dt_01_concept_04",
      "winnerId": "dt_01_concept_01",
      "reason": "01 uses existing fish waste, which is highly believable and appetizing. 04's seaweed might be a harder sell as a primary food source or business in the 80s compared to fish roe."
    },
    {
      "leftId": "dt_01_concept_01",
      "rightId": "dt_01_concept_05",
      "winnerId": "dt_01_concept_01",
      "reason": "01's loop of finding waste, cooking, and selling is a more direct and satisfying realization of 'làm giàu bằng tay nghề' than 05's indirect logistics approach."
    },
    {
      "leftId": "dt_01_concept_01",
      "rightId": "dt_01_concept_06",
      "winnerId": "dt_01_concept_01",
      "reason": "01 fits the 'chế biến' and 'bữa cơm' requirements perfectly, offering daily, tangible results. 06 is more mechanical and less directly tied to the daily seafood harvest loop."
    },
    {
      "leftId": "dt_01_concept_01",
      "rightId": "dt_01_concept_07",
      "winnerId": "dt_01_concept_07",
      "reason": "Both are excellent, but 07 has a clearer path to scaling and marketization (drying, sorting, packaging) over 30 chapters. 01 is slightly limited by the daily supply of fish waste."
    },
    {
      "leftId": "dt_01_concept_01",
      "rightId": "dt_01_concept_08",
      "winnerId": "dt_01_concept_01",
      "reason": "08 borders on the forbidden 'tọa độ chính xác' by having the MC find a new cockle bed. 01 relies purely on processing skill and agency."
    },
    {
      "leftId": "dt_01_concept_01",
      "rightId": "dt_01_concept_09",
      "winnerId": "dt_01_concept_01",
      "reason": "01 provides a much better and more immediate 'bữa cơm đủ' (full meal) than 09's salt sorting."
    },
    {
      "leftId": "dt_01_concept_01",
      "rightId": "dt_01_concept_10",
      "winnerId": "dt_01_concept_01",
      "reason": "10's tourism concept is completely out of place for the 1980s setting. 01 is highly authentic."
    },
    {
      "leftId": "dt_01_concept_02",
      "rightId": "dt_01_concept_03",
      "winnerId": "dt_01_concept_03",
      "reason": "02's fish sauce fermentation is too slow to meet the Ch 1-3 'thành quả sớm' requirement. 03 provides immediate results through gear repair."
    },
    {
      "leftId": "dt_01_concept_02",
      "rightId": "dt_01_concept_04",
      "winnerId": "dt_01_concept_04",
      "reason": "04 provides immediate results as seaweed processing takes a day. 02's fermentation takes months, failing the early pacing requirement."
    },
    {
      "leftId": "dt_01_concept_02",
      "rightId": "dt_01_concept_05",
      "winnerId": "dt_01_concept_05",
      "reason": "05 provides immediate value by saving ice overnight. 02 is too slow for the opening requirements."
    },
    {
      "leftId": "dt_01_concept_02",
      "rightId": "dt_01_concept_06",
      "winnerId": "dt_01_concept_06",
      "reason": "06 provides immediate results through boat modification. 02's timeline is too stretched for the first 5 chapters."
    },
    {
      "leftId": "dt_01_concept_02",
      "rightId": "dt_01_concept_07",
      "winnerId": "dt_01_concept_07",
      "reason": "07's drying process yields quick results, fitting the fast pacing. 02's fish sauce takes too long to show a state change."
    },
    {
      "leftId": "dt_01_concept_02",
      "rightId": "dt_01_concept_08",
      "winnerId": "dt_01_concept_08",
      "reason": "08 provides an immediate catch. 02's mechanism is inherently too slow for the required chapter pacing."
    }
  ]
}
